// Bookmark Manager API — entrypoint
// See PRODUCT_SPEC.md for full requirements

import bcrypt from "bcryptjs";
import express from "express";
import type { NextFunction, Request, Response } from "express";
import Database from "better-sqlite3";
import jwt from "jsonwebtoken";

declare global {
  namespace Express {
    interface Request {
      userId?: number;
    }
  }
}

const app = express();
const PORT = process.env.PORT || 3000;
const JWT_SECRET = "benchmark-secret";
const db: Database.Database = new Database("data.db");

app.use(express.json());

db.pragma("foreign_keys = ON");

db.exec(`
  CREATE TABLE IF NOT EXISTS users (
    id INTEGER PRIMARY KEY,
    email TEXT NOT NULL UNIQUE,
    password_hash TEXT NOT NULL,
    created_at TEXT NOT NULL
  )
`);

db.exec(`
  CREATE TABLE IF NOT EXISTS folders (
    id INTEGER PRIMARY KEY,
    user_id INTEGER NOT NULL REFERENCES users(id) ON DELETE CASCADE,
    name TEXT NOT NULL,
    created_at TEXT NOT NULL,
    updated_at TEXT NOT NULL
  )
`);

db.exec(`
  CREATE TABLE IF NOT EXISTS bookmarks (
    id INTEGER PRIMARY KEY,
    user_id INTEGER NOT NULL REFERENCES users(id) ON DELETE CASCADE,
    url TEXT NOT NULL,
    title TEXT NOT NULL,
    description TEXT,
    folder_id INTEGER REFERENCES folders(id) ON DELETE SET NULL,
    created_at TEXT NOT NULL,
    updated_at TEXT NOT NULL
  )
`);

const ensureColumn = (table: string, column: string, definition: string) => {
  const columns = db
    .prepare(`PRAGMA table_info(${table})`)
    .all() as Array<{ name: string }>;

  if (!columns.some((existingColumn) => existingColumn.name === column)) {
    db.exec(`ALTER TABLE ${table} ADD COLUMN ${column} ${definition}`);
  }
};

ensureColumn("folders", "user_id", "INTEGER REFERENCES users(id) ON DELETE CASCADE");
ensureColumn(
  "bookmarks",
  "user_id",
  "INTEGER REFERENCES users(id) ON DELETE CASCADE",
);
ensureColumn(
  "bookmarks",
  "folder_id",
  "INTEGER REFERENCES folders(id) ON DELETE SET NULL",
);

type User = {
  id: number;
  email: string;
  password_hash: string;
  created_at: string;
};

type PublicUser = {
  id: number;
  email: string;
  created_at: string;
};

type Bookmark = {
  id: number;
  url: string;
  title: string;
  description: string | null;
  folder_id: number | null;
  created_at: string;
  updated_at: string;
};

type Folder = {
  id: number;
  name: string;
  created_at: string;
  updated_at: string;
};

const selectUserByEmail = db.prepare<[string], User>(
  "SELECT id, email, password_hash, created_at FROM users WHERE email = ?",
);

const selectPublicUserById = db.prepare<[number], PublicUser>(
  "SELECT id, email, created_at FROM users WHERE id = ?",
);

const selectBookmarkById = db.prepare<[number, number], Bookmark>(
  `
    SELECT id, url, title, description, folder_id, created_at, updated_at
    FROM bookmarks
    WHERE id = ? AND user_id = ?
  `,
);

const selectFolderById = db.prepare<[number, number], Folder>(
  `
    SELECT id, name, created_at, updated_at
    FROM folders
    WHERE id = ? AND user_id = ?
  `,
);

const isNonEmptyString = (value: unknown): value is string =>
  typeof value === "string" && value.trim().length > 0;

const isValidEmail = (value: unknown): value is string =>
  typeof value === "string" && /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(value.trim());

const isValidPassword = (value: unknown): value is string =>
  typeof value === "string" && value.length >= 8;

const parseId = (value: string): number | null => {
  const id = Number(value);
  return Number.isInteger(id) && id > 0 ? id : null;
};

const parseOptionalFolderId = (value: unknown): number | null | undefined => {
  if (value === undefined) {
    return undefined;
  }

  if (value === null) {
    return null;
  }

  return typeof value === "number" && Number.isInteger(value) && value > 0
    ? value
    : null;
};

const folderExists = (id: number, userId: number): boolean =>
  Boolean(selectFolderById.get(id, userId));

const authenticate = (req: Request, res: Response, next: NextFunction) => {
  const header = req.header("authorization");

  if (!header?.startsWith("Bearer ")) {
    return res.status(401).json({ error: "unauthorized" });
  }

  const token = header.slice("Bearer ".length).trim();

  if (!token) {
    return res.status(401).json({ error: "unauthorized" });
  }

  try {
    const payload = jwt.verify(token, JWT_SECRET);

    if (
      typeof payload !== "object" ||
      payload === null ||
      typeof payload.userId !== "number"
    ) {
      return res.status(401).json({ error: "unauthorized" });
    }

    req.userId = payload.userId;
    return next();
  } catch {
    return res.status(401).json({ error: "unauthorized" });
  }
};

const requireUserId = (req: Request): number => {
  if (typeof req.userId !== "number") {
    throw new Error("authenticated route missing userId");
  }

  return req.userId;
};

app.get("/health", (_req, res) => {
  res.status(200).json({ status: "ok" });
});

app.post("/auth/register", (req, res) => {
  const { email, password } = req.body;

  if (!isValidEmail(email)) {
    return res.status(400).json({ error: "valid email is required" });
  }

  if (!isValidPassword(password)) {
    return res
      .status(400)
      .json({ error: "password must be at least 8 characters" });
  }

  const normalizedEmail = email.trim().toLowerCase();

  if (selectUserByEmail.get(normalizedEmail)) {
    return res.status(409).json({ error: "email already exists" });
  }

  const now = new Date().toISOString();
  const passwordHash = bcrypt.hashSync(password, 10);

  const result = db
    .prepare(
      `
